def grade_share_rule(model, g, m):
    return model.outp[g, m] <= 0.6 * sum(model.outp[g, mm] for mm in model.m)
model.grade_share = Constraint(model.g, model.m, rule=grade_share_rule)

def min_share_rule(model, g, m):
    return model.outp[g, m] >= 0.20 * model.dempr_demand[g]
model.min_share = Constraint(model.g, model.m, rule=min_share_rule)

def machine_min_rule(model, mc):
    return sum(model.outp[g, mc] for g in model.g) >= 0.25 * sum(model.outp[g, m2] for g in model.g for m2 in model.m)
model.machine_min = Constraint(model.m, rule=machine_min_rule)

def machine_max_rule(model, mc):
    return sum(model.outp[g, mc] for g in model.g) <= 0.40 * sum(model.outp[g, m2] for g in model.g for m2 in model.m)
model.machine_max = Constraint(model.m, rule=machine_max_rule)
